1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PRICE = 60;
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	
21	const countByType = (items: Item[]): Record<string, number> => {
22	  const counts: Record<string, number> = {};
23	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
24	  return counts;
25	};
26	
27	const lineItemPrice = (type: string, count: number): number => {
28	  const isBlock = COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
29	  return isBlock ? COMPONENT_BLOCK_PRICE : BASE_PREMIUM[type] * count;
30	};
31	
32	const sumBasePremiums = (items: Item[]): number =>
33	  Object.entries(countByType(items))
34	    .reduce((total, [type, count]) => total + lineItemPrice(type, count), 0);
35	
36	const quotePremium = (items: Item[]): number => {
37	  const basePremium = sumBasePremiums(items);
38	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
39	  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
40	};
41	
42	export const runScenario = (input: unknown): unknown => {
43	  const scenario = input as Scenario;
44	  const results = scenario.steps.map(({ items }) => ({ premium: quotePremium(items) }));
45	  return { results };
46	};
